window.__QUIZ_DATA__=[{"id":"objective>Office Practice>2020>1","subject":"Office Practice","year":"2020","type":"Objective","topic":"MEETINGS : TYPES","question":"A meeting of AYEX Plc board of directors would be categorized as","images":[],"options":{"A":"formal meeting","B":"informal meeting","C":"stakeholder meeting","D":"staff meeting"},"answer":"A","explanation":"A meeting of a company's board of directors is a formal meeting. This is because it is usually structured, follows a set agenda, and is often documented in minutes. Informal meetings are less structured and may not follow a set agenda. Stakeholder meetings involve various parties who have an interest in the company, while staff meetings involve employees of the company.","marks":"1","difficulty":"2"},{"id":"objective>Office Practice>2020>2","subject":"Office Practice","year":"2020","type":"Objective","topic":"FILING : CLASSIFICATION OF FILING","question":"In alphabetical filing, professional titles are written","images":[],"options":{"A":"after the names of people","B":"in between the initials of people","C":"after the surname of people","D":"before the second name of people"},"answer":"A","explanation":"In alphabetical filing, professional titles are written after the names of people. This is because the primary sorting criterion in alphabetical filing is the name (usually the surname) of the individual. The professional title is secondary information and is therefore written after the name.","marks":"1","difficulty":"1"},{"id":"objective>Office Practice>2020>3","subject":"Office Practice","year":"2020","type":"Objective","topic":"COMMUNICATION : METHODS/MEDIA OF COMMUNICATION","question":"An advantages of oral communication is that it","images":[],"options":{"A":"provides a permanent record of idea shared","B":"carries more weight than other types of communication","C":"is more formal than written communication","D":"allows both parties concern to feel each other's mood"},"answer":"D","explanation":"Oral communication allows both parties to feel each other's mood. This is because it involves direct face-to-face conversation, which allows for immediate feedback and the ability to read non-verbal cues, such as body language and tone of voice. This is not possible in other forms of communication like written communication.","marks":"1","difficulty":"2"},{"id":"objective>Office Practice>2020>4","subject":"Office Practice","year":"2020","type":"Objective","topic":"MAILS : PROCEDURES FOR HANDLING INCOMING AND OUTGOING MAILS","question":"Incoming mails should be sorted according to","images":[],"options":{"A":"sizes","B":"weighs","C":"departments","D":"contents"},"answer":"C","explanation":"Incoming mails should be sorted according to departments. This is because each department in an organization typically handles different aspects of the business, and therefore, the information contained in the mails would be relevant to specific departments. Sorting mails according to departments ensures that the right information gets to the right people in a timely manner.","marks":"1","difficulty":"1"},{"id":"objective>Office Practice>2020>5","subject":"Office Practice","year":"2020","type":"Objective","topic":"MEETINGS : PROCEDURES FOR CONDUCTING A MEETING","question":"One of the common items included in the agenda of meeting is","images":[],"options":{"A":"security issues in different parts of the country","B":"security of members at the meeting","C":"matters arising from the minutes of previous meeting","D":"matters arising from the current meeting"},"answer":"C","explanation":"One of the common items included in the agenda of a meeting is 'matters arising from the minutes of the previous meeting'. This is because it is important to follow up on the issues discussed in the previous meeting, check the progress made, and determine if any further action is needed. This helps to ensure that all issues are addressed and nothing is overlooked.","marks":"1","difficulty":"2"},{"id":"objective>Office Practice>2020>6","subject":"Office Practice","year":"2020","type":"Objective","topic":"OFFICE CORRESPONDENCE : MEANING OF OFFICE CORRESPONDENCE","question":"Which of the following items in a letter is an example of complimentary close?","images":[],"options":{"A":"Dear sir","B":"Yours faithfully","C":"Attention: Mr Smith","D":"cc: Mrs Dauda"},"answer":"B","explanation":"The complimentary close in a letter is a polite way of ending the letter. It usually comes before the signature and after the body of the letter. 'Yours faithfully' is an example of a complimentary close.","marks":"1","difficulty":"1"},{"id":"objective>Office Practice>2020>7","subject":"Office Practice","year":"2020","type":"Objective","topic":"OFFICE DOCUMENTS : MEANING OF OFFICE DOCUMENT","question":"The implication of issuing a crossed cheque is that it can only be","images":[],"options":{"A":"cashed at the counter","B":"cash after six month of its issue","C":"lodged into the current account of the payee","D":"lodged into the fixed deposit account"},"answer":"C","explanation":"A crossed cheque is a cheque that has been marked to specify an instruction about the way it is to be redeemed. A crossed cheque cannot be immediately cashed at a bank counter but must be deposited into the bank account of the payee.","marks":"1","difficulty":"2"},{"id":"objective>Office Practice>2020>8","subject":"Office Practice","year":"2020","type":"Objective","topic":"REPORT WRITINGS : PARTS OF A REPORT","question":"The part of a report that suggets solution to the problem investigated is the","images":[],"options":{"A":"body of report","B":"recommendation","C":"terms of reference","D":"introduction"},"answer":"B","explanation":"The recommendation section of a report is where the author suggests solutions to the problems investigated in the report. It is where the author gives their advice on what actions should be taken.","marks":"1","difficulty":"2"},{"id":"objective>Office Practice>2020>9","subject":"Office Practice","year":"2020","type":"Objective","topic":"OFFICE CORRESPONDENCE : TYPES","question":"An official written message to several people at different destinations on the same subject matter is","images":[],"options":{"A":"memo","B":"letter","C":"circular","D":"report"},"answer":"C","explanation":"A circular is an official written message that is sent to several people at different destinations on the same subject matter. It is used to communicate the same information to a large number of people. A memo is a note or record made for future use. A letter is a written message from one party to another containing information. A report is a formal account of the facts or details of a matter.","marks":"1","difficulty":"2"},{"id":"objective>Office Practice>2020>10","subject":"Office Practice","year":"2020","type":"Objective","topic":"MAILS : PROCEDURES FOR HANDLING INCOMING AND OUTGOING MAILS","question":"Confidential mail is opened by the","images":[],"options":{"A":"secretary","B":"mail room staff","C":"personnel unit staff","D":"receptionist"},"answer":"B","explanation":"Mail romm staff is a person who works in a mailroom and is known as a mailroom clerk or mailboy and the head person (sometimes the only person is called the postmaster.The mailroom is responsible for a company's incoming and outgoing mail.","marks":"1","difficulty":"1"},{"id":"objective>Office Practice>2020>11","subject":"Office Practice","year":"2020","type":"Objective","topic":"MEETINGS : PROCEDURES FOR CONDUCTING A MEETING","question":"A form of corresponding sent to members asking them to attend a meeting is","images":[],"options":{"A":"the minutes","B":"an invite","C":"a notice","D":"an agenda"},"answer":"C","explanation":"A notice is a form of correspondence sent to members asking them to attend a meeting. It serves to inform members about the meeting and its details such as the date, time, and venue. An invite is a request, encouragement, or opportunity to do something. The minutes are the official record of the proceedings of a meeting. An agenda is a list of items to be discussed at a formal meeting.","marks":"1","difficulty":"1"},{"id":"objective>Office Practice>2020>12","subject":"Office Practice","year":"2020","type":"Objective","topic":"OFFICE DOCUMENTS : USES","question":"Business document are used for passing information on business transactions among","images":[],"options":{"A":"buyers of goods and services only","B":"sellers of goods and services only","C":"buyer and sellers of goods and services only","D":"competitors of the organization only"},"answer":"C","explanation":"Business documents are used for passing information on business transactions among both buyers and sellers of goods and services. These documents can include things like invoices, receipts, purchase orders, and more. They are used to keep track of transactions, provide legal protection, and ensure clear communication between parties.","marks":"1","difficulty":"1"},{"id":"objective>Office Practice>2020>13","subject":"Office Practice","year":"2020","type":"Objective","topic":"MEETINGS : TYPES","question":"A meeting held by all employees of an organization is","images":[],"options":{"A":"a committee meeting","B":"an emergency meeting","C":"a staff meeting","D":"an annual general meeting"},"answer":"C","explanation":"A meeting held by all employees of an organization is typically referred to as a staff meeting. This is a regular meeting where information is shared, updates are given, and issues are discussed. It's a way for everyone in the organization to stay informed and aligned.","marks":"1","difficulty":"1"},{"id":"objective>Office Practice>2020>14","subject":"Office Practice","year":"2020","type":"Objective","topic":"FILING : STEPS IN FILING","question":"The act of weeding out redundant documents in the files is","images":[],"options":{"A":"up-dating of records","B":"thining of records","C":"destruction of records","D":"removing of records"},"answer":"B","explanation":"The act of weeding out redundant documents in the files is referred to as thinning of records. This process involves removing duplicate, outdated, or unnecessary documents from a file or record system. It's a way to keep records organized and manageable, and to ensure that the most relevant and up-to-date information is easily accessible.","marks":"1","difficulty":"1"},{"id":"objective>Office Practice>2020>15","subject":"Office Practice","year":"2020","type":"Objective","topic":"REPORT WRITINGS : TYPES","question":"A report written regularly to give an account of an event or work carried out is","images":[],"options":{"A":"a periodic report","B":"a statutory report","C":"a routine report","D":"an informal report"},"answer":"C","explanation":"A routine report is a type of report that is written on a regular or scheduled basis. This could be daily, weekly, monthly, or annually. It is used to provide an update or give an account of an event or work carried out regularly. A periodic report is also regular but it is not necessarily about an event or work carried out. A statutory report is a report that is legally required, while an informal report is a casual report usually meant for internal distribution.","marks":"1","difficulty":"1"},{"id":"objective>Office Practice>2020>16","subject":"Office Practice","year":"2020","type":"Objective","topic":"OFFICE EQUIPMENT : TYPES OF OFFICE EQUIPMENT","question":"An electirc device which process data into information by following a set of programme instructions is","images":[],"options":{"A":"computer","B":"teleprinter","C":"photocopier","D":"calculator"},"answer":"A","explanation":"A computer is an electronic device that manipulates information, or data. It has the ability to store, retrieve, and process data. It follows a set of program instructions to process data into information. A teleprinter is a telegraph machine that can send and receive messages, a photocopier is a machine that makes paper copies of documents and other visual images, and a calculator is a device that is used for performing numerical calculations.","marks":"1","difficulty":"1"},{"id":"objective>Office Practice>2020>17","subject":"Office Practice","year":"2020","type":"Objective","topic":"COMMUNICATION : METHODS/MEDIA OF COMMUNICATION","question":"The first step the sender takes into the communication process is to","images":[],"options":{"A":"transmit the message","B":"encode the message","C":"select an appropriate channel","D":"give a feedback"},"answer":"B","explanation":"The first step in the communication process is to encode the message. Encoding is the process of turning thoughts into communication. The sender has an intention to communicate and hence, creates a message in their mind, which is then encoded in a way that can be understood by the receiver. Transmitting the message, selecting an appropriate channel, and giving feedback are subsequent steps in the communication process.","marks":"1","difficulty":"2"},{"id":"objective>Office Practice>2020>18","subject":"Office Practice","year":"2020","type":"Objective","topic":"MEETINGS : WRITING THE MINUTES","question":"A record of the proceedings of a meeting that is circulated to members is the","images":[],"options":{"A":"quorum","B":"agenda","C":"minutes","D":"motion"},"answer":"C","explanation":"The record of the proceedings of a meeting that is circulated to members is known as the 'minutes'. Minutes are the written record of a meeting or hearing. They typically describe the events of the meeting, starting with a list of attendees, a statement of the issues considered by the participants, and related responses or decisions for the issues.","marks":"1","difficulty":"2"},{"id":"objective>Office Practice>2020>19","subject":"Office Practice","year":"2020","type":"Objective","topic":"COMMUNICATION : DEFINITION OF COMMUNICATION","question":"Which of the following is a barrier to effective communication?","images":[],"options":{"A":"Encoding","B":"Decoding","C":"Channel","D":"Noise"},"answer":"D","explanation":"Noise is a barrier to effective communication. In the context of communication, 'noise' refers to anything that distorts the message, making it difficult for the receiver to understand the message as intended by the sender. This could be physical noise (like loud sounds) or psychological noise (like distractions, stress, or language differences).","marks":"1","difficulty":"2"},{"id":"objective>Office Practice>2020>20","subject":"Office Practice","year":"2020","type":"Objective","topic":"FILING : SYSTEMS OF FILING","question":"A system whereby all files and records of an organization are kept and controlled in one room is","images":[],"options":{"A":"decentralized filing","B":"vertical filing","C":"centralized filing","D":"horizontal filing"},"answer":"C","explanation":"A system whereby all files and records of an organization are kept and controlled in one room is known as 'centralized filing'. Centralized filing is a structured filing system in one location. It is easier to control and coordinate and it ensures that the files are safe and easily accessible when needed.","marks":"1","difficulty":"2"},{"id":"objective>Office Practice>2020>21","subject":"Office Practice","year":"2020","type":"Objective","topic":"REPORT WRITINGS : PARTS OF A REPORT","question":"The part of a report giving a detailed explanation of how a committe carried out its assignment is the","images":[],"options":{"A":"introduction","B":"terms of reference","C":"body","D":"recommendation"},"answer":"C","explanation":"The body of a report is where the detailed explanation of how a committee carried out its assignment is found. The introduction usually provides a brief overview of the report's content, the terms of reference define the purpose and structure of the report, and the recommendation is where suggestions or conclusions are made based on the findings in the report.","marks":"1","difficulty":"2"},{"id":"objective>Office Practice>2020>22","subject":"Office Practice","year":"2020","type":"Objective","topic":"OFFICE EQUIPMENT : TYPES OF OFFICE EQUIPMENT","question":"An advantage of eletric typewriter over manual typewriter is that","images":[],"options":{"A":"they are faster and increase output","B":"they are less expensive to buy","C":"the cost of maintenance is lower","D":"they can be easily moved from place to place"},"answer":"A","explanation":"Electric typewriters are indeed faster and increase output compared to manual typewriters. This is because electric typewriters are powered by electricity and have keys that require less force to press, resulting in faster typing speeds. The other options are incorrect as electric typewriters are generally more expensive to buy, have higher maintenance costs due to their complexity, and are not easily portable due to their reliance on electricity.","marks":"1","difficulty":"1"},{"id":"objective>Office Practice>2020>23","subject":"Office Practice","year":"2020","type":"Objective","topic":"DEPARTMENTS IN AN ORGANIZATION : FUNCTIONS OF EACH DEPARTMENT","question":"The purchasing department in an organization is responsible for","images":[],"options":{"A":"procurring goods for the organization","B":"selling ggods for the organization","C":"advertising goods for the organization","D":"recording goods for the organization"},"answer":"A","explanation":"The purchasing department in an organization is responsible for procuring goods for the organization. This involves identifying suppliers, negotiating contracts, and ensuring that the goods are delivered on time and meet the organization's quality standards. The other options are incorrect as selling, advertising, and recording goods are typically responsibilities of the sales, marketing, and inventory departments respectively.","marks":"1","difficulty":"1"},{"id":"objective>Office Practice>2020>24","subject":"Office Practice","year":"2020","type":"Objective","topic":"THE RECEPTION : MEANING OF RECEPTIONIST","question":"Use the following information to answer questions below:  Adams has just been employed by a large organization as the first person whom callers and visitors would see when visiting the organization    Which of the following postion does Adams occupy in the organization?","images":[],"options":{"A":"Manager","B":"Supervisor","C":"Receptionist","D":"Secretary"},"answer":"C","explanation":"The first person whom callers and visitors would see when visiting an organization is typically the Receptionist. The receptionist's role is to greet visitors and direct them to the appropriate person or department. They also handle incoming calls and often perform administrative tasks.","marks":"1","difficulty":"1"},{"id":"objective>Office Practice>2020>25","subject":"Office Practice","year":"2020","type":"Objective","topic":"COMMUNICATION : IMPORTANCE","question":"Use the following information to answer questions below:  Adams has just been employed by a large organization as the first person whom callers and visitors would see when visiting the organizationIn order to perform his duties well,Adams must be able to","images":[],"options":{"A":"communicate effectively","B":"supervise effectively","C":"coordinate effectively","D":"handle mails effectively"},"answer":"A","explanation":"In order to perform his duties well, Adams must be able to communicate effectively. As a receptionist, he will be interacting with a variety of people, including clients, visitors, and staff members. Effective communication skills are essential to ensure that information is conveyed accurately and professionally.","marks":"1","difficulty":"2"},{"id":"objective>Office Practice>2020>26","subject":"Office Practice","year":"2020","type":"Objective","topic":"THE RECEPTION : DOCUMENTS HANDLED BY A RECEPTIONIST","question":"Use the following information to answer questions below:  Adams has just been employed by a large organization as the first person whom callers and visitors would see when visiting the organizationTo keep records of callers and clients who come for the organization,Adams office must be provided with","images":[],"options":{"A":"attendance register","B":"visitors' book","C":"mail register","D":"dispatch book"},"answer":"B","explanation":"To keep records of callers and clients who come for the organization, Adams' office must be provided with a visitors' book. This is a record where visitors sign in with their name, the date and time of their visit, who they are seeing and their purpose of visit. It helps the organization keep track of who is coming and going.","marks":"1","difficulty":"1"},{"id":"objective>Office Practice>2020>27","subject":"Office Practice","year":"2020","type":"Objective","topic":"THE OFFICE : LAYOUT OF AN OFFICE","question":"A feature of an open office is that","images":[],"options":{"A":"all the doors are opened","B":"all the cabinets are opened","C":"workers are put together in the same room","D":"each worker occupies a separate room"},"answer":"C","explanation":"An open office is a type of office layout where all or most employees work in the same room, often at desks arranged in a grid pattern. This layout is designed to facilitate communication and collaboration among employees. Therefore, the correct answer is 'workers are put together in the same room'.","marks":"1","difficulty":"2"},{"id":"objective>Office Practice>2020>28","subject":"Office Practice","year":"2020","type":"Objective","topic":"MAILS : PROCEDURES FOR HANDLING INCOMING AND OUTGOING MAILS","question":"The first step a mail clerk takes in handling outgoing mail is to","images":[],"options":{"A":"collect typed letters from various departments","B":"attach all enclosure that are to accompany each mail","C":"date-stamp the envelop in which each letter is inverted","D":"ensure that each mail envelop is well-sealed"},"answer":"A","explanation":"The first step a mail clerk takes in handling outgoing mail is to collect the typed letters from various departments. This is because before any other action can be taken, such as attaching enclosures or date-stamping envelopes, the mail clerk must first have the letters that are to be sent out.","marks":"1","difficulty":"2"},{"id":"objective>Office Practice>2020>29","subject":"Office Practice","year":"2020","type":"Objective","topic":"INFORMATION : STORAGE OF INFORMATION","question":"The means of making miniature copies of records for storage is","images":[],"options":{"A":"indexing","B":"microfilming","C":"cross-referencing","D":"jogger"},"answer":"B","explanation":"Microfilming is a process that involves making miniature copies of documents for storage. This is done by photographing the documents and storing the images on film. When needed, the images can be enlarged and viewed. Therefore, the correct answer is 'microfilming'.","marks":"1","difficulty":"1"},{"id":"objective>Office Practice>2020>30","subject":"Office Practice","year":"2020","type":"Objective","topic":"COMMUNICATION : METHODS/MEDIA OF COMMUNICATION","question":"Information on a specific project to all members of a section is communicated through","images":[],"options":{"A":"departmental meetings","B":"board meetings","C":"annual meetings","D":"executive meetings"},"answer":"A","explanation":"Information on a specific project to all members of a section is usually communicated through departmental meetings. This is because departmental meetings are designed to disseminate information and discuss matters that concern a specific department or section within an organization. Board meetings, annual meetings, and executive meetings are typically for higher-level strategic discussions and may not involve all members of a specific section.","marks":"1","difficulty":"2"},{"id":"objective>Office Practice>2020>31","subject":"Office Practice","year":"2020","type":"Objective","topic":"INFORMATION : TYPES","question":"The information written on a paper would be regarded as the","images":[],"options":{"A":"soft copy","B":"blind copy","C":"hard copy","D":"photocopy"},"answer":"C","explanation":"The information written on a paper would be regarded as the hard copy. A hard copy is a physical version of information, such as a document, that is printed on paper. In contrast, a soft copy is a digital version of these documents, which can be stored and viewed on a computer. A blind copy refers to sending emails to recipients in such a way that they can't see the other recipients, and a photocopy is a duplicate of a document or print made on a photocopier.","marks":"1","difficulty":"1"},{"id":"objective>Office Practice>2020>32","subject":"Office Practice","year":"2020","type":"Objective","topic":"COMMUNICATION : METHODS/MEDIA OF COMMUNICATION","question":"A memo is used in an office for","images":[],"options":{"A":"internal communication","B":"oral communication","C":"external communication","D":"audio communication"},"answer":"A","explanation":"A memo (short for memorandum) is a type of document used in businesses for internal communication. Memos are typically used within an organization to communicate information, changes, or updates to employees. Therefore, memos are not used for oral, external, or audio communication.","marks":"1","difficulty":"1"},{"id":"objective>Office Practice>2020>33","subject":"Office Practice","year":"2020","type":"Objective","topic":"OFFICE EQUIPMENT : MEANING OF OFFICE EQUIPMENT","question":"One of the disdavantages of using office machine is that it leads to","images":[],"options":{"A":"reduction in running cost","B":"low productivity","C":"low quality of work","D":"staff redundancy"},"answer":"D","explanation":"The use of office machines can lead to staff redundancy. This is because machines can often perform tasks more efficiently and quickly than humans, reducing the need for human labor. This can lead to job losses, which is a major disadvantage of using office machines.","marks":"1","difficulty":"1"},{"id":"objective>Office Practice>2020>34","subject":"Office Practice","year":"2020","type":"Objective","topic":"OFFICE DOCUMENTS : PREPARATION OF OFFICE DOCUMENTS","question":"Price list is issued by the seller to","images":[],"options":{"A":"make enquires about products and their prices","B":"serve as reply to a customer's enquiry","C":"make order for goods and services","D":"make enquires about products and means of payment"},"answer":"B","explanation":"A price list is issued by the seller to serve as a reply to a customer's enquiry. It provides information about the products and their prices, allowing the customer to make an informed decision about their purchase.","marks":"1","difficulty":"1"},{"id":"objective>Office Practice>2020>35","subject":"Office Practice","year":"2020","type":"Objective","topic":"MAILS : PROCEDURES FOR HANDLING INCOMING AND OUTGOING MAILS","question":"Which of the following headings is a column in a postage book","images":[],"options":{"A":"Date of dispatch","B":"Value of stamp used","C":"Reference number","D":"Title of document"},"answer":"B","explanation":"A postage book is a record of all the mail that has been sent out, including the value of the stamp used. This allows for tracking of expenses and ensures that the correct amount of postage is being used for each item.","marks":"1","difficulty":"1"},{"id":"objective>Office Practice>2020>36","subject":"Office Practice","year":"2020","type":"Objective","topic":"OFFICE EQUIPMENT : TYPES OF OFFICE EQUIPMENT","question":"The machine used to produce large number of copies of a document from the","images":[],"options":{"A":"electronic typewriter","B":"collating machine","C":"duplicating machine","D":"scanning machine"},"answer":"C","explanation":"A duplicating machine is used to produce a large number of copies of a document. This process is also known as duplication. The machine works by creating a master copy of the document, which is then used to produce the copies. The other options listed do not perform this function. An electronic typewriter is used for typing, a collating machine is used for arranging papers in a specific order, and a scanning machine is used for creating digital copies of documents.","marks":"1","difficulty":"1"},{"id":"objective>Office Practice>2020>37","subject":"Office Practice","year":"2020","type":"Objective","topic":"DEPARTMENTS IN AN ORGANIZATION : ORGANIZATIONAL CHART","question":"Use the diagram below to answer questions below       The downward arrows shows","images":["data:image/png;base64,"],"options":{"A":"supervisory relationship","B":"lateral relationship","C":"reporting relationship","D":"lateral and reporting relationships"},"answer":"D","explanation":"Lateral relationship/structural arrangement consists of a decentralized structure in which departments works together to acheive a common goal rather than operate as separate and distinct entities.","marks":"1","difficulty":"3"},{"id":"objective>Office Practice>2020>38","subject":"Office Practice","year":"2020","type":"Objective","topic":"DEPARTMENTS IN AN ORGANIZATION : ORGANIZATIONAL CHART","question":"Use the diagram below to answer questions below     The upward arrows shows","images":["data:image/png;base64,"],"options":{"A":"supervisory relationship","B":"lateral relationship","C":"reporting relationship","D":"lateral and reporting relationships"},"answer":"A","explanation":"Supervisory relationship is merely a way of connecting a supervisor who is more experienced or an expertise, with a supervisee who lacks this experience.Both of them have some common goals and work together to acheive these goals.","marks":"1","difficulty":"3"},{"id":"objective>Office Practice>2020>39","subject":"Office Practice","year":"2020","type":"Objective","topic":"FILING : CLASSIFICATION OF FILING","question":"Use the diagram below to answer questions below     Which of the following names comes first in alphabetical filing?","images":["data:image/png;base64,"],"options":{"A":"R.A.D Johnson","B":"A.R.D Johnson","C":"Dr. R.A.D Johnson","D":"Dr. A.R.D Johnson"},"answer":"D","explanation":"Alphabetical filing is a method in which files and folders are arranged in order of alphabets of the names of person or institution concerned with such file. It may be dome using either the first names or surnames, but whichever is chosen must be consistent throughout the particular filing system. However, initial comes first before the names.","marks":"1","difficulty":"3"},{"id":"objective>Office Practice>2020>40","subject":"Office Practice","year":"2020","type":"Objective","topic":"THE OFFICE : FUNCTIONS OF OFFICE","question":"One of the functions of an office is to safeguard","images":[],"options":{"A":"information","B":"assets","C":"payment vouchers","D":"visitor's book"},"answer":"A","explanation":"One of the primary functions of an office is to safeguard information. This includes data, records, and any other form of information that is crucial to the operation of the organization. While assets, payment vouchers, and visitor's books are also important, they are not the primary function of an office.","marks":"1","difficulty":"1"},{"id":"objective>Office Practice>2020>41","subject":"Office Practice","year":"2020","type":"Objective","topic":"MAILS : PROCEDURES FOR HANDLING INCOMING AND OUTGOING MAILS","question":"In a large organization,mails handling is done in the","images":[],"options":{"A":"reception","B":"registry","C":"general office","D":"secretary's office"},"answer":"B","explanation":"In a large organization, mail handling is typically done in the registry. The registry is responsible for receiving, sorting, and distributing mail within the organization. The reception is usually the first point of contact for visitors, the general office handles a variety of administrative tasks, and the secretary's office is typically responsible for supporting the work of a specific individual or department.","marks":"1","difficulty":"2"},{"id":"objective>Office Practice>2020>42","subject":"Office Practice","year":"2020","type":"Objective","topic":"OFFICE EQUIPMENT : TYPES OF OFFICE EQUIPMENT","question":"The office machine used for fastening papers together is a","images":[],"options":{"A":"perforator","B":"stapler","C":"fokling machine","D":"sealing machine"},"answer":"B","explanation":"A stapler is an office tool that is used to join together pages of paper or similar material by driving a thin metal staple through the sheets and folding the ends. Therefore, the correct answer is a stapler.","marks":"1","difficulty":"1"},{"id":"objective>Office Practice>2020>43","subject":"Office Practice","year":"2020","type":"Objective","topic":"THE OFFICE : LAYOUT OF AN OFFICE","question":"One of the advantages of a closed office is that","images":[],"options":{"A":"the supervisor can see all workers at a glance","B":"it is easy to construct","C":"office equipment can be jointly used","D":"it ensure confidentially of documents"},"answer":"D","explanation":"A closed office layout is a type of office layout where all the office spaces are divided by walls and each employee has their own separate office space. This type of office layout is beneficial for jobs that require concentration, privacy and confidentiality. Therefore, the correct answer is 'it ensures confidentiality of documents'.","marks":"1","difficulty":"2"},{"id":"objective>Office Practice>2020>44","subject":"Office Practice","year":"2020","type":"Objective","topic":"FILING : CLASSIFICATION OF FILING","question":"The appropriate filing classification for an organization having clients in different locations is","images":[],"options":{"A":"alphabetical","B":"numerical","C":"chronological","D":"geographical"},"answer":"D","explanation":"Geographical filing is a method where files and folders are arranged in order of geographical location. This method is useful for organizations that operate in different geographical locations. Therefore, the correct answer is 'geographical'.","marks":"1","difficulty":"2"},{"id":"objective>Office Practice>2020>45","subject":"Office Practice","year":"2020","type":"Objective","topic":"COMMUNICATION : DEFINITION OF COMMUNICATION","question":"The exchange of information among individuals is","images":[],"options":{"A":"coding","B":"decoding","C":"communication","D":"feedback"},"answer":"C","explanation":"Communication is the process of exchanging information or ideas between two or more individuals. Coding and decoding are parts of the communication process, while feedback is a response to the communication.","marks":"1","difficulty":"1"},{"id":"objective>Office Practice>2020>46","subject":"Office Practice","year":"2020","type":"Objective","topic":"COMMUNICATION : METHODS/MEDIA OF COMMUNICATION","question":"An example of traditional method of communication is","images":[],"options":{"A":"drumming","B":"telephoning","C":"letter writing","D":"speech making"},"answer":"A","explanation":"Drumming is a traditional method of communication, especially in African societies. Telephoning, letter writing, and speech making are modern methods of communication.","marks":"1","difficulty":"1"},{"id":"objective>Office Practice>2020>47","subject":"Office Practice","year":"2020","type":"Objective","topic":"INFORMATION : SOURCES","question":"The source of business information which gives spellings and meanings of words is the","images":[],"options":{"A":"diary","B":"dictionary","C":"directory","D":"harzard"},"answer":"B","explanation":"A dictionary is a source of business information that provides spellings and meanings of words. A diary is a record of personal experiences and observations, a directory is a list of names, addresses, and other details, and a hazard is a potential source of danger.","marks":"1","difficulty":"1"},{"id":"objective>Office Practice>2020>48","subject":"Office Practice","year":"2020","type":"Objective","topic":"THE OFFICE : FUNCTIONS OF OFFICE","question":"Which of the following activities is a function of an office?","images":[],"options":{"A":"Receiving information","B":"Punishing late comers","C":"Calculating of workers salaries","D":"Welcoming visitors"},"answer":"A","explanation":"An office function involves the management and distribution of information. This includes receiving, processing, storing, and disseminating information. Therefore, 'Receiving information' is a function of an office.","marks":"1","difficulty":"1"},{"id":"objective>Office Practice>2020>49","subject":"Office Practice","year":"2020","type":"Objective","topic":"MEETINGS : TYPES","question":"An executive committee can be described as one which","images":[],"options":{"A":"has no power to ratift decisions of other committees","B":"has power to ratify decisions of other committees","C":"is dissolved on the completion of its assignment","D":"has no fixed assignment"},"answer":"B","explanation":"An executive committee is a smaller group of a larger board or organization that has the power to make decisions on behalf of the larger group. This includes the power to ratify decisions of other committees. Therefore, 'has power to ratify decisions of other committees' is the correct answer.","marks":"1","difficulty":"2"},{"id":"objective>Office Practice>2020>50","subject":"Office Practice","year":"2020","type":"Objective","topic":"OFFICE DOCUMENTS : MEANING OF OFFICE DOCUMENT","question":"The part of a letter which makes it an authentic office document is the","images":[],"options":{"A":"address","B":"salutation","C":"enclosure","D":"signature"},"answer":"D","explanation":"The signature part of a letter is what makes it an authentic office document. It is the signatory's endorsement of the content of the letter. Therefore, 'signature' is the correct answer.","marks":"1","difficulty":"1"}];